html, body {
  margin: 0;
  height: 100%;
  overflow: hidden;
  background: #f5f5f5;
}

#canvas {
  position: fixed;
  inset: 0;
  width: 100vw;
  height: 100vh;
  touch-action: none;
  cursor: crosshair;
  background: #ffffff;
}

#toolbar {
  position: fixed;
  top: 12px;
  left: 12px;
  display: flex;
  gap: 12px;
  align-items: center;
  padding: 8px 12px;
  background: rgba(255, 255, 255, 0.9);
  backdrop-filter: blur(6px);
  border: 1px solid #ddd;
  border-radius: 8px;
  font-size: 13px;
  user-select: none;
}

#toolbar label {
  display: flex;
  align-items: center;
  gap: 6px;
}

#toolbar button {
  font: inherit;
  padding: 4px 10px;
  border: 1px solid #ccc;
  background: #fafafa;
  border-radius: 4px;
  cursor: pointer;
}

#toolbar button:hover {
  background: #efefef;
}

